mapper.update:
update wf_cc_order 
set status = #{status}, 
finish_Time = #{finishTime} 
where order_Id = #{orderId} and actor_Id = #{actorId}

mapper.select:
		select order_Id, actor_Id, creator, create_Time, finish_Time, status 
		from wf_cc_order 


                order_Id = #{orderId}


                and actor_Id in

                    #{actorId}

		select count(id) from wf_cc_order cc left join wf_hist_order o on cc.order_id = o.id


                cc.actor_Id in

                    #{operator}



                and cc.status = #{request.state}


                and process_Id = #{request.processId}


                and parent_Id = #{request.parentId}


                and cc.create_Time >= #{request.createTimeStart}


                and cc.create_Time <= #{request.createTimeEnd}


                and order_No = #{request.orderNo}

		select id, process_Id, order_State, priority, cc.creator, cc.create_Time, end_Time, parent_Id, expire_Time,
		order_No, variable
		from wf_cc_order cc left join wf_hist_order o on cc.order_id = o.id


                cc.actor_Id in

                    #{operator}



                and cc.status = #{request.state}


                and process_Id = #{request.processId}


                and parent_Id = #{request.parentId}


                and cc.create_Time >= #{request.createTimeStart}


                and cc.create_Time <= #{request.createTimeEnd}


                and order_No = #{request.orderNo}


		order by #{request.orderBy} #{request.order}
		limit #{rowOffset}, #{request.pageSize}
